import { describe, test, expect, vi, beforeEach, afterEach } from 'vitest';
import * as fs from 'node:fs';
import * as path from 'node:path';
import { mkdtempSync, rmSync, mkdirSync, writeFileSync } from 'node:fs';
import { tmpdir } from 'node:os';

// ---------------------------------------------------------------------------
// Mocks
// ---------------------------------------------------------------------------

const FAKE_PLUGIN_ROOT = mkdtempSync(path.join(tmpdir(), 'first-run-'));

vi.mock('../../lib/common.js', () => ({
  logHook: vi.fn(),
  getPluginRoot: vi.fn(() => FAKE_PLUGIN_ROOT),
  outputWithContext: vi.fn((msg: string) => ({
    continue: true,
    suppressOutput: false,
    hookSpecificOutput: { additionalContext: msg },
  })),
}));

vi.mock('../../lib/atomic-write.js', () => ({
  atomicWriteSync: vi.fn((filePath: string, content: string) => {
    const dir = path.dirname(filePath);
    if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
    fs.writeFileSync(filePath, content);
  }),
}));

// Mock child_process — we control which tools are "available"
const mockExecFileSync = vi.fn();
vi.mock('node:child_process', () => ({
  execFileSync: (...args: unknown[]) => mockExecFileSync(...args),
}));

import { firstRunSetup } from '../../setup/first-run-setup.js';
import { outputWithContext } from '../../lib/common.js';
import type { HookInput } from '../../types.js';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function createHookInput(overrides: Partial<HookInput> = {}): HookInput {
  return {
    tool_name: '',
    session_id: 'test-session-first-run',
    project_dir: FAKE_PLUGIN_ROOT,
    tool_input: {},
    ...overrides,
  };
}

/** Seed enough file-system structure so component counting works */
function seedPluginRoot() {
  const hooksDir = path.join(FAKE_PLUGIN_ROOT, 'hooks', 'pretool');
  mkdirSync(hooksDir, { recursive: true });
  for (let i = 0; i < 5; i++) {
    writeFileSync(path.join(hooksDir, `h-${i}.sh`), '#!/bin/bash\n');
  }

  for (let i = 0; i < 3; i++) {
    const skillDir = path.join(FAKE_PLUGIN_ROOT, 'skills', `s-${i}`);
    mkdirSync(skillDir, { recursive: true });
    writeFileSync(path.join(skillDir, 'SKILL.md'), '# S\n');
  }

  const agentsDir = path.join(FAKE_PLUGIN_ROOT, 'agents');
  mkdirSync(agentsDir, { recursive: true });
  writeFileSync(path.join(agentsDir, 'a.md'), '# A\n');
}

/** Configure execFileSync mock so all tools are "found" */
function mockAllToolsAvailable() {
  mockExecFileSync.mockImplementation((cmd: string, args: string[]) => {
    if (cmd === 'python3' && args?.[0] === '--version') return 'Python 3.12.1\n';
    if (cmd === 'node' && args?.[0] === '--version') return 'v20.11.0\n';
    if (cmd === 'which') return '/usr/bin/thing\n';
    if (cmd === 'python3' && args?.[0] === '-c') return '';
    return '';
  });
}

/** Configure execFileSync mock so required dep (jq) is missing */
function mockJqMissing() {
  mockExecFileSync.mockImplementation((cmd: string, args: string[]) => {
    if (cmd === 'python3' && args?.[0] === '--version') return 'Python 3.12.1\n';
    if (cmd === 'node' && args?.[0] === '--version') return 'v20.11.0\n';
    if (cmd === 'which' && args?.[0] === 'jq') throw new Error('not found');
    if (cmd === 'which') return '/usr/bin/thing\n';
    if (cmd === 'python3' && args?.[0] === '-c') throw new Error('no module');
    return '';
  });
}

// ---------------------------------------------------------------------------
// Setup / teardown
// ---------------------------------------------------------------------------

const originalArgv = [...process.argv];

beforeEach(() => {
  vi.clearAllMocks();
  process.argv = [...originalArgv];
  rmSync(FAKE_PLUGIN_ROOT, { recursive: true, force: true });
  mkdirSync(FAKE_PLUGIN_ROOT, { recursive: true });
});

afterEach(() => {
  process.argv = [...originalArgv];
});

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe('first-run-setup', () => {
  // =========================================================================
  // Happy path — full setup
  // =========================================================================

  describe('happy path', () => {
    test('completes setup and creates marker file', () => {
      // Arrange
      seedPluginRoot();
      mockAllToolsAvailable();

      // Act
      const result = firstRunSetup(createHookInput());

      // Assert
      expect(result.continue).toBe(true);

      const markerPath = path.join(FAKE_PLUGIN_ROOT, '.setup-complete');
      expect(fs.existsSync(markerPath)).toBe(true);

      const marker = JSON.parse(fs.readFileSync(markerPath, 'utf-8'));
      expect(marker.version).toBe('4.25.0');
      expect(marker.preset).toBe('complete');
      expect(marker.components.hooks.count).toBeGreaterThanOrEqual(5);
      expect(marker.components.skills.count).toBeGreaterThanOrEqual(3);
      expect(marker.user_preferences.onboarding_completed).toBe(true);
    });

    test('creates config.json in .claude/defaults/', () => {
      // Arrange
      seedPluginRoot();
      mockAllToolsAvailable();

      // Act
      firstRunSetup(createHookInput());

      // Assert
      const configPath = path.join(FAKE_PLUGIN_ROOT, '.claude', 'defaults', 'config.json');
      expect(fs.existsSync(configPath)).toBe(true);
      const config = JSON.parse(fs.readFileSync(configPath, 'utf-8'));
      expect(config.preset).toBe('complete');
      expect(config.features.skills).toBe(true);
    });

    test('creates required directories', () => {
      // Arrange
      seedPluginRoot();
      mockAllToolsAvailable();

      // Act
      firstRunSetup(createHookInput());

      // Assert
      expect(fs.existsSync(path.join(FAKE_PLUGIN_ROOT, '.claude', 'defaults'))).toBe(true);
      expect(fs.existsSync(path.join(FAKE_PLUGIN_ROOT, '.claude', 'context', 'session'))).toBe(true);
      expect(fs.existsSync(path.join(FAKE_PLUGIN_ROOT, '.claude', 'context', 'knowledge'))).toBe(true);
      expect(fs.existsSync(path.join(FAKE_PLUGIN_ROOT, '.claude', 'logs'))).toBe(true);
    });

    test('makes hook .sh files executable', () => {
      // Arrange
      seedPluginRoot();
      mockAllToolsAvailable();
      // Create a non-executable .sh
      const hookPath = path.join(FAKE_PLUGIN_ROOT, 'hooks', 'pretool', 'test.sh');
      writeFileSync(hookPath, '#!/bin/bash\n');
      fs.chmodSync(hookPath, 0o644);

      // Act
      firstRunSetup(createHookInput());

      // Assert
      const stats = fs.statSync(hookPath);
      expect(stats.mode & 0o111).toBeTruthy();
    });
  });

  // =========================================================================
  // Dependency validation failure
  // =========================================================================

  describe('dependency validation', () => {
    test('returns error when jq is missing', () => {
      // Arrange
      seedPluginRoot();
      mockJqMissing();

      // Act
      const result = firstRunSetup(createHookInput());

      // Assert
      expect(vi.mocked(outputWithContext)).toHaveBeenCalled();
      const msg = vi.mocked(outputWithContext).mock.calls[0][0];
      expect(msg).toContain('failed');
      expect(msg).toContain('jq');
    });
  });

  // =========================================================================
  // Interactive vs silent mode
  // =========================================================================

  describe('mode selection', () => {
    test('interactive mode includes version and skill count in output', () => {
      // Arrange
      seedPluginRoot();
      mockAllToolsAvailable();
      // No --silent flag

      // Act
      const result = firstRunSetup(createHookInput());

      // Assert
      expect(vi.mocked(outputWithContext)).toHaveBeenCalled();
      const msg = vi.mocked(outputWithContext).mock.calls[0][0];
      expect(msg).toContain('4.25.0');
      expect(msg).toContain('skills');
    });

    test('silent mode produces shorter output', () => {
      // Arrange
      seedPluginRoot();
      mockAllToolsAvailable();
      process.argv = [...originalArgv, '--silent'];

      // Act
      firstRunSetup(createHookInput());

      // Assert
      const msg = vi.mocked(outputWithContext).mock.calls[0][0];
      expect(msg).toContain('silent mode');
    });
  });

  // =========================================================================
  // Preset configs
  // =========================================================================

  describe('getPresetConfig (via applyConfiguration)', () => {
    test('does not overwrite existing config.json', () => {
      // Arrange
      seedPluginRoot();
      mockAllToolsAvailable();
      const configDir = path.join(FAKE_PLUGIN_ROOT, '.claude', 'defaults');
      mkdirSync(configDir, { recursive: true });
      writeFileSync(path.join(configDir, 'config.json'), JSON.stringify({ preset: 'lite', custom: true }));

      // Act
      firstRunSetup(createHookInput());

      // Assert — existing config preserved
      const config = JSON.parse(fs.readFileSync(path.join(configDir, 'config.json'), 'utf-8'));
      expect(config.preset).toBe('lite');
      expect(config.custom).toBe(true);
    });
  });

  // =========================================================================
  // Environment detection
  // =========================================================================

  describe('environment detection', () => {
    test('detects python version from output', () => {
      // Arrange
      seedPluginRoot();
      mockAllToolsAvailable();

      // Act
      firstRunSetup(createHookInput());

      // Assert — marker should contain environment info
      const markerPath = path.join(FAKE_PLUGIN_ROOT, '.setup-complete');
      const marker = JSON.parse(fs.readFileSync(markerPath, 'utf-8'));
      expect(marker.environment.python).toBe('3.12');
      expect(marker.environment.nodejs).toBe('20.11');
      expect(marker.environment.git).toBe(true);
    });

    test('handles missing python gracefully', () => {
      // Arrange
      seedPluginRoot();
      mockExecFileSync.mockImplementation((cmd: string, args: string[]) => {
        if (cmd === 'python3') throw new Error('not found');
        if (cmd === 'node' && args?.[0] === '--version') return 'v20.11.0\n';
        if (cmd === 'which' && args?.[0] === 'jq') return '/usr/bin/jq\n';
        if (cmd === 'which') return '/usr/bin/thing\n';
        return '';
      });

      // Act
      const result = firstRunSetup(createHookInput());

      // Assert — should still succeed
      expect(result.continue).toBe(true);
      const marker = JSON.parse(
        fs.readFileSync(path.join(FAKE_PLUGIN_ROOT, '.setup-complete'), 'utf-8')
      );
      expect(marker.environment.python).toBeUndefined();
    });
  });

  // =========================================================================
  // Edge case: empty plugin root
  // =========================================================================

  describe('edge cases', () => {
    test('handles empty plugin root without crashing', () => {
      // Arrange — no seed, empty root
      mockAllToolsAvailable();

      // Act
      const result = firstRunSetup(createHookInput());

      // Assert
      expect(result.continue).toBe(true);
      expect(fs.existsSync(path.join(FAKE_PLUGIN_ROOT, '.setup-complete'))).toBe(true);
    });
  });
});
